import React, { useEffect, useState } from 'react';
import Column from '../Column';
import * as C from './style';

function Main({ pedidos, pageRender }) {

    const [ pedidos1, setPedidos1 ] = useState([]);
    const [ pedidos2, setPedidos2 ] = useState([]);
    const [ pedidos3, setPedidos3 ] = useState([]);
    const [ pedidos4, setPedidos4 ] = useState([]);
    const [ pedidos5, setPedidos5 ] = useState([]);

    
    
    if(pedidos.length > 0){
        setPedidos1(pedidos.filter( e => e.horaEntrega === "19:30"))
        setPedidos2(pedidos.filter( e => e.horaEntrega === "20:00"))
        setPedidos3(pedidos.filter( e => e.horaEntrega === "20:30"))
        setPedidos4(pedidos.filter( e => e.horaEntrega === "21:00"))
        setPedidos5(pedidos.filter( e => e.horaEntrega === "21:30"))
    }

    if(pageRender === "Pedidos"){
        return (
            <C.ContainerPedidos>
                <Column title='19:30' pedidos={pedidos1}/>
                <Column title='20:00' pedidos={pedidos2}/>
                <Column title='20:30' pedidos={pedidos3}/>
                <Column title='21:00' pedidos={pedidos4}/>
                <Column title='21:30' pedidos={pedidos5}/>
            </C.ContainerPedidos>
        )
    }

    if(pageRender === "Produtos"){
        
    }
    
}

export default Main
